1	export type Item = { kind: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone" };
2	
3	export type QuoteStep = { kind: "quote"; items: Item[] };
4	
5	export type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: QuoteStep[];
8	};
9	
10	export type ScenarioResult = {
11	  results: unknown[];
12	};
13	
14	const COMPONENT_BASE_PREMIUM = 25;
15	
16	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: COMPONENT_BASE_PREMIUM,
22	  moonstone: COMPONENT_BASE_PREMIUM,
23	};
24	
25	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
26	const PROCESSING_FEE = 5;
27	
28	function basePremiumFor(item: Item): number {
29	  return BASE_PREMIUM_BY_ITEM[item.kind];
30	}
31	
32	type QuoteResult = { kind: "quote"; premium: number };
33	
34	function quoteStep(step: QuoteStep): QuoteResult {
35	  const basePremium = step.items.reduce((sum, item) => sum + basePremiumFor(item), 0);
36	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
37	  const premium = Math.ceil(basePremium + surcharge + PROCESSING_FEE);
38	  return { kind: "quote", premium };
39	}
40	
41	export function processScenario(scenario: Scenario): ScenarioResult {
42	  const results = scenario.steps.map(quoteStep);
43	  return { results };
44	}
